+import "@perf-profiler/e2e/src/utils/test/mockChildProcess";
+import {
+  emitMeasures,
+  perfProfilerMock,
+  aTraceMock,
+} from "@perf-profiler/e2e/src/utils/test/mockEmitMeasures";
+import { fireEvent, render as webRender, screen, waitFor, act } from "@testing-library/react";
+import { render as cliRender } from "ink-testing-library";
+import { MeasureWebApp } from "../webapp/MeasureWebApp";
+import React from "react";
+import { ServerApp } from "../server/ServerApp";
+import { open } from "@perf-profiler/shell";
+import { matchSnapshot } from "@perf-profiler/web-reporter-ui/utils/testUtils";
+import { removeCLIColors } from "./utils/removeCLIColors";
+import { LogLevel, Logger } from "@perf-profiler/logger";
+
+jest.mock("@perf-profiler/shell", () => ({
+  open: jest.fn(),
+}));
+
+Math.random = () => 0.5;
+
+// Set me to LogLevel.DEBUG to see the debug logs
+Logger.setLogLevel(LogLevel.SILENT);
+
+describe("flashlight measure interactive", () => {
+  const expectWebAppToBeOpened = () =>
+    waitFor(() => expect(open).toHaveBeenCalledWith("http://localhost:3000"));
+
+  const setupCli = () => {
+    const { lastFrame, unmount } = cliRender(<ServerApp />);
+    const closeCli = async () => {
+      unmount();
+      // Seems like we need to wait for the useEffect cleanup to happen
+      await new Promise((resolve) => setTimeout(resolve, 0));
+    };
+
+    return {
+      closeCli,
+      expectCliOutput: () => expect(removeCLIColors(lastFrame())),
+    };
+  };
+
+  const setupWebApp = () => {
+    // eslint-disable-next-line testing-library/render-result-naming-convention
+    const renderer = webRender(<MeasureWebApp />);
+
+    return {
+      closeWebApp: renderer.unmount,
+      expectWebAppToMatchSnapshot: (snapshotName: string) => matchSnapshot(renderer, snapshotName),
+    };
+  };
+
+  test("it displays measures", async () => {
+    const { closeCli, expectCliOutput } = setupCli();
+    const { closeWebApp, expectWebAppToMatchSnapshot } = setupWebApp();
+    await expectWebAppToBeOpened();
+
+    expectCliOutput().toMatchInlineSnapshot(`
+      "
+       Flashlight web app running on: http://localhost:3000
+      "
+    `);
+
+    // Autodetect app id com.example
+    await screen.findByText("Auto-Detect");
+    fireEvent.click(screen.getByText("Auto-Detect"));
+    await screen.findByDisplayValue("com.example");
+
+    // Start measuring
+    fireEvent.click(screen.getByText("Start Measuring"));
+
+    // Initial report screen with no measures
+    await screen.findByText("Average Test Runtime");
+    expectWebAppToMatchSnapshot("Web app with no measures yet");
+
+    // Simulate measures being emitted on the device
+    act(() => emitMeasures());
+
+    // Find the score!
+    await screen.findByText("47");
+
+    // expand threads
+    await screen.findByText("Threads");
+    fireEvent.click(screen.getByText("Threads"));
+
+    expectWebAppToMatchSnapshot("Web app with measures and threads opened");
+
+    // Stop measuring
+    fireEvent.click(screen.getByText("Stop Measuring"));
+    await waitFor(() => expect(aTraceMock.kill).toBeCalled());
+    await waitFor(() => expect(perfProfilerMock.kill).toBeCalled());
+
+    // Close apps
+
+    await closeCli();
+    closeWebApp();
+  });
+});

diff --git a/packages/commands/test/src/__tests__/PerformanceMeasurer.test.ts b/packages/commands/test/src/__tests__/PerformanceMeasurer.test.ts
new file mode 100644
index 0000000..82060ad
--- /dev/null
+++ b/packages/commands/test/src/__tests__/PerformanceMeasurer.test.ts
@@ -0,0 +1,38 @@
+import "../utils/test/mockChildProcess";
+import { LogLevel, Logger } from "@perf-profiler/logger";
+import { PerformanceMeasurer } from "../PerformanceMeasurer";
+import { emitMeasure, perfProfilerMock } from "../utils/test/mockEmitMeasures";
+
+Logger.setLogLevel(LogLevel.SILENT);
+
+const loggerDebug = jest.spyOn(Logger, "debug");
+const loggerError = jest.spyOn(Logger, "error");
+
+describe("PerformanceMeasurer", () => {
+  it("handles c++ errors correctly", () => {
+    const measurer = new PerformanceMeasurer("com.example");
+    measurer.start();
+    emitMeasure(0);
+    emitMeasure(1);
+    perfProfilerMock.stderr?.emit("data", "CPP_ERROR_CANNOT_OPEN_FILE /proc/1234/tasks/578/stat");
+    emitMeasure(2);
+
+    expect(loggerDebug).toHaveBeenCalledWith(
+      "CPP_ERROR_CANNOT_OPEN_FILE /proc/1234/tasks/578/stat"
+    );
+    expect(loggerError).not.toHaveBeenCalled();
+
+    expect(measurer.measures).toHaveLength(2);
+    expect(measurer.measures).toMatchSnapshot();
+
+    // Reset measures when pid changes
+    perfProfilerMock.stderr?.emit("data", "CPP_ERROR_MAIN_PID_CLOSED 1234");
+    emitMeasure(0);
+    expect(measurer.measures).toHaveLength(0);
+
+    emitMeasure(1);
+    emitMeasure(2);
+
+    expect(measurer.measures).toHaveLength(2);
+  });
+});

diff --git a/packages/core/web-reporter-ui/__tests__/ReporterView.test.tsx b/packages/core/web-reporter-ui/__tests__/ReporterView.test.tsx
new file mode 100644
index 0000000..2a69fdf
--- /dev/null
+++ b/packages/core/web-reporter-ui/__tests__/ReporterView.test.tsx
@@ -0,0 +1,59 @@
+import React from "react";
+import { render, fireEvent, screen } from "@testing-library/react";
+import { IterationsReporterView } from "../ReporterView";
+import { TestCaseResult } from "@perf-profiler/types";
+import { getText } from "../utils/testUtils";
+
+describe("<ReporterView />", () => {
+  it("renders the comparison view", () => {
+    const testCaseResults: TestCaseResult[] = [
+      require("../../../commands/report/src/example-reports/results1.json"),
+      require("../../../commands/report/src/example-reports/results2.json"),
+    ];
+
+    const { asFragment, baseElement } = render(
+      <IterationsReporterView results={testCaseResults} />
+    );
